-- MATCALL Database Setup
-- Generated from CSV export
-- Run in Supabase SQL Editor

-- =============================================
-- STEP 1: CREATE TABLES
-- =============================================

create table if not exists master_plant (
  id            bigserial primary key,
  plant_code    text not null unique,
  plant_name    text not null,
  email_pan     text,
  email_plan    text,
  email_rw      text,
  email_pd      text,
  email_manager text,
  is_active     boolean default true,
  created_at    timestamptz default now(),
  updated_at    timestamptz default now()
);

create table if not exists master_supplier (
  id               bigserial primary key,
  material_name    text not null,
  material_no      text,
  plant            text references master_plant(plant_code),
  supplier_name    text not null,
  supplier_email   text,
  contract_start   date,
  contract_end     date,
  quota_percent    numeric(5,2),
  total_quota      numeric(14,2),
  remaining_quota  numeric(14,2),
  created_at       timestamptz default now(),
  updated_at       timestamptz default now()
);
create index if not exists idx_ms_plant_mat_sup on master_supplier(plant, material_name, supplier_name);

create table if not exists calloff_plan (
  id                   bigserial primary key,
  title                text,
  plant                text references master_plant(plant_code),
  material_name        text,
  supplier_name        text,
  delivery_date        date,
  quantity             numeric(14,2),
  unit                 text default 'kg',
  tank_id              text,
  target_week          text,
  status               text default 'Active',
  remark               text,
  mail_status          text default 'Pending',
  do_number            text,
  supplier_weight      numeric(14,2),
  factory_weight       numeric(14,2),
  weight_diff          numeric(14,2),
  sap_receive_weight   numeric(14,2),
  sap_doc_number       text,
  actual_delivery_date date,
  receive_status       text default 'Pending',
  created_at           timestamptz default now(),
  updated_at           timestamptz default now()
);
create index if not exists idx_cp_plant_date on calloff_plan(plant, delivery_date);
create index if not exists idx_cp_mail on calloff_plan(mail_status);
create index if not exists idx_cp_receive on calloff_plan(receive_status);
create index if not exists idx_cp_supplier on calloff_plan(supplier_name);

-- =============================================
-- STEP 2: ENABLE RLS & POLICIES
-- =============================================
alter table master_plant    enable row level security;
alter table master_supplier enable row level security;
alter table calloff_plan    enable row level security;

drop policy if exists "allow_all" on calloff_plan;
drop policy if exists "allow_all" on master_plant;
drop policy if exists "allow_all" on master_supplier;

create policy "allow_all" on calloff_plan    for all using (true) with check (true);
create policy "allow_all" on master_plant    for all using (true) with check (true);
create policy "allow_all" on master_supplier for all using (true) with check (true);

